import{_ as t,o as n,c as r,ai as e}from"./chunks/framework.SowO7O0D.js";const b=JSON.parse('{"title":"第九课：K线基础","description":"","frontmatter":{},"headers":[],"relativePath":"guide/09-kline-basics.md","filePath":"guide/09-kline-basics.md","lastUpdated":0}'),s={name:"guide/09-kline-basics.md"};function l(i,a,o,d,h,p){return n(),r("div",null,[...a[0]||(a[0]=[e(`<h1 id="第九课-k线基础" tabindex="-1">第九课：K线基础 <a class="header-anchor" href="#第九课-k线基础" aria-label="Permalink to “第九课：K线基础”">​</a></h1><p>K线是技术分析的基本功。这一课让你从零看懂K线图。</p><h2 id="一、k线是什么" tabindex="-1">一、K线是什么？ <a class="header-anchor" href="#一、k线是什么" aria-label="Permalink to “一、K线是什么？”">​</a></h2><p>K线（蜡烛图）是一种<strong>记录股价走势的图形</strong>，每个K线代表一段时间：</p><ul><li><strong>日K</strong>：每天一根</li><li><strong>周K</strong>：每周一根</li><li><strong>月K</strong>：每月一根</li></ul><h2 id="二、k线的构成" tabindex="-1">二、K线的构成 <a class="header-anchor" href="#二、k线的构成" aria-label="Permalink to “二、K线的构成”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>     最高价</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>  开盘 │ 收盘</span></span>
<span class="line"><span>  ─────┤     ← 实体</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>     最低价</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>每个K线有<strong>4个价格</strong>：开盘价、收盘价、最高价、最低价</p><h2 id="三、红涨绿跌-a股规则" tabindex="-1">三、红涨绿跌（A股规则） <a class="header-anchor" href="#三、红涨绿跌-a股规则" aria-label="Permalink to “三、红涨绿跌（A股规则）”">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>颜色</th><th>条件</th></tr></thead><tbody><tr><td>阳线</td><td>红色（涨）</td><td>收盘价 &gt; 开盘价</td></tr><tr><td>阴线</td><td>绿色（跌）</td><td>收盘价 &lt; 开盘价</td></tr></tbody></table><blockquote><p>💡 注意：有些软件用红涨绿跌，有些相反，要注意区分。</p></blockquote><h2 id="四、单根k线的含义" tabindex="-1">四、单根K线的含义 <a class="header-anchor" href="#四、单根k线的含义" aria-label="Permalink to “四、单根K线的含义”">​</a></h2><h3 id="_1-大阳线-长红实体" tabindex="-1">1. 大阳线（长红实体） <a class="header-anchor" href="#_1-大阳线-长红实体" aria-label="Permalink to “1. 大阳线（长红实体）”">​</a></h3><p><strong>形态</strong>：实体很长，几乎没有上下影线</p><p><strong>含义</strong>：买盘强劲，多方完全主导。大涨信号。</p><h3 id="_2-大阴线-长绿实体" tabindex="-1">2. 大阴线（长绿实体） <a class="header-anchor" href="#_2-大阴线-长绿实体" aria-label="Permalink to “2. 大阴线（长绿实体）”">​</a></h3><p><strong>形态</strong>：实体很长，几乎没有上下影线</p><p><strong>含义</strong>：卖盘强劲，空方完全主导。大跌信号。</p><h3 id="_3-十字星" tabindex="-1">3. 十字星 <a class="header-anchor" href="#_3-十字星" aria-label="Permalink to “3. 十字星”">​</a></h3><p><strong>形态</strong>：开盘=收盘，上下影线差不多长</p><p><strong>含义</strong>：多空博弈平衡，是<strong>转折信号</strong>，但方向不确定。</p><h3 id="_4-上影线很长" tabindex="-1">4. 上影线很长 <a class="header-anchor" href="#_4-上影线很长" aria-label="Permalink to “4. 上影线很长”">​</a></h3><p><strong>形态</strong>：上方影线很长，实体小</p><p><strong>含义</strong>：冲高回落，上方卖压大。<strong>偏弱信号</strong>。</p><h3 id="_5-下影线很长" tabindex="-1">5. 下影线很长 <a class="header-anchor" href="#_5-下影线很长" aria-label="Permalink to “5. 下影线很长”">​</a></h3><p><strong>形态</strong>：下方影线很长，实体小</p><p><strong>含义</strong>：探底回升，下方支撑强。<strong>偏强信号</strong>。</p><h2 id="五、k线组合-入门级" tabindex="-1">五、K线组合（入门级） <a class="header-anchor" href="#五、k线组合-入门级" aria-label="Permalink to “五、K线组合（入门级）”">​</a></h2><h3 id="_1-吞没形态" tabindex="-1">1. 吞没形态 <a class="header-anchor" href="#_1-吞没形态" aria-label="Permalink to “1. 吞没形态”">​</a></h3><p><strong>看涨吞没</strong>：绿色小实体 + 红色大实体完全包裹</p><p><strong>看跌吞没</strong>：红色小实体 + 绿色大实体完全包裹</p><h3 id="_2-早晨之星-底部反转" tabindex="-1">2. 早晨之星（底部反转） <a class="header-anchor" href="#_2-早晨之星-底部反转" aria-label="Permalink to “2. 早晨之星（底部反转）”">​</a></h3><p>三根K线组合：</p><ol><li>大阴线（跌）</li><li>小实体（震荡）</li><li>大阳线（涨）</li></ol><p><strong>含义</strong>：行情可能见底回升</p><h3 id="_3-黄昏之星-顶部反转" tabindex="-1">3. 黄昏之星（顶部反转） <a class="header-anchor" href="#_3-黄昏之星-顶部反转" aria-label="Permalink to “3. 黄昏之星（顶部反转）”">​</a></h3><p>三根K线组合：</p><ol><li>大阳线（涨）</li><li>小实体（震荡）</li><li>大阴线（跌）</li></ol><p><strong>含义</strong>：行情可能见顶回落</p><h2 id="六、怎么看k线周期" tabindex="-1">六、怎么看K线周期？ <a class="header-anchor" href="#六、怎么看k线周期" aria-label="Permalink to “六、怎么看K线周期？”">​</a></h2><table tabindex="0"><thead><tr><th>周期</th><th>用途</th></tr></thead><tbody><tr><td>日K</td><td>看短期走势，做短线参考</td></tr><tr><td>周K</td><td>看中期趋势，辅助判断方向</td></tr><tr><td>月K</td><td>看长期趋势，判断大方向</td></tr></tbody></table><blockquote><p>💡 新手建议主要看<strong>日K和周K</strong>，月K太长，容易看不清细节。</p></blockquote><h2 id="七、k线的局限性" tabindex="-1">七、K线的局限性 <a class="header-anchor" href="#七、k线的局限性" aria-label="Permalink to “七、K线的局限性”">​</a></h2><blockquote><p>⚠️ <strong>K线是辅助工具，不是预测神器。</strong></p></blockquote><ul><li>K线只能反映<strong>已经发生的事</strong></li><li>主力可以&quot;画K线&quot;（故意做出某种形态引诱散户）</li><li>要结合成交量、均线、消息面一起看</li></ul><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>某股票连续3天收了上影线很长的K线，这意味着什么？</p></blockquote><hr><p><strong>下一课预告</strong>：K线基础会了，下一课学习<strong>均线系统</strong>——如何用均线判断趋势。</p>`,49)])])}const g=t(s,[["render",l]]);export{b as __pageData,g as default};
